import http from 'k6/http';
import { check } from 'k6';
import { Trend, Rate } from 'k6/metrics';

const searchDurationTrend = new Trend('search_duration');
const searchErrorRate = new Rate('search_errors');

export default function() {
    const response = searchRequest('id-searches', '{}');

    const success = check(response, {
        'status is 200': (r) => r.status === 200,
    });

    // Log and track errors if the request fails
    if (!success) {
        searchErrorRate.add(1);
        console.error(`Search request failed with status ${response.status}. Response: ${response.body}`);
    } else {
        searchErrorRate.add(0);
    }

    // Add the response duration to the custom trend metric
    searchDurationTrend.add(response.timings.duration);

    // Optional: log the duration for each request
    console.log(`Request duration: ${response.timings.duration} ms`);
}

